sql:
SELECT COUNT(*) AS bid_count
FROM team_bids
WHERE bid_type_id = 1;

SELECT team_id, COUNT(*) AS number_of_bids
FROM team_bids
GROUP BY team_id;

SELECT name 
FROM teams 
ORDER BY name;
